#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int x1, y1, x2, y2;
        scanf("%d %d %d %d", &x1, &y1, &x2, &y2);
        if (x1 == x2 || y1 == y2) {
            printf("YES\n");
        } else {
            printf("NO\n");
        }
    }
    return 0;
}

